最近一段时间在学习java，寒假学过一部分内容了，这里写个笔记来简单记录一下java的学习。(中文独享版)
Java 语法学习总结一、基本语法1. 变量与数据类型1234567891011// 基本数据类型int age = 20;double height = 1.75;boolean isStudent = true;char grade = &#x27;A&#x27;;// 字符串String name = &quot;张三&quot;;// 变量声明int num1, num2, num3;

2. 运算符123456789101112131415// 算术运算符int sum = 10 + 20;int difference = 20 - 10;int product = 10 * 20;int quotient = 20 / 10;int remainder = 20 % 3;// 关系运算符boolean isEqual = (10 == 20);boolean isGreater = (20 &gt; 10);// 逻辑运算符boolean andResult = (true &amp;&amp; false);boolean orResult = (true || false);boolean notResult = !true;

3. 控制结构123456789101112131415161718192021222324252627282930//if语句if (condition) &#123;    // 执行代码&#125; else if (anotherCondition) &#123;    // 执行代码&#125; else &#123;    // 执行代码&#125;//switch语句switch (expression) &#123;    case value1:        // 执行代码        break;    case value2:        // 执行代码        break;    default:        // 执行代码&#125;//while循环while (condition) &#123;    // 执行代码&#125;//do-while循环do &#123;    // 执行代码&#125; while (condition);

二、面向对象编程1. 类与对象123456789101112131415161718192021// 定义类public class Person &#123;    // 成员变量    String name;    int age;    // 构造方法    public Person(String name, int age) &#123;        this.name = name;        this.age = age;    &#125;    // 成员方法    public void introduce() &#123;        System.out.println(&quot;我叫&quot; + name + &quot;，今年&quot; + age + &quot;岁。&quot;);    &#125;&#125;// 创建对象Person person = new Person(&quot;张三&quot;, 20);person.introduce();
2. 继承1234567891011121314151617// 父类public class Animal &#123;    public void eat() &#123;        System.out.println(&quot;动物在吃东西。&quot;);    &#125;&#125;// 子类public class Dog extends Animal &#123;    public void bark() &#123;        System.out.println(&quot;狗在叫。&quot;);    &#125;&#125;Dog dog = new Dog();dog.eat(); // 继承自父类的方法dog.bark(); // 子类自己的方法
3.多态1234567891011// 父类引用指向子类对象Animal animal = new Dog();animal.eat(); // 调用子类重写的方法（如果有的话）// 方法重写public class Dog extends Animal &#123;    @Override    public void eat() &#123;        System.out.println(&quot;狗在吃狗粮。&quot;);    &#125;&#125;
4. 接口123456789101112// 定义接口public interface Runnable &#123;    void run();&#125;// 实现接口public class Dog implements Runnable &#123;    @Override    public void run() &#123;        System.out.println(&quot;狗在跑。&quot;);    &#125;&#125;
三、异常处理12345678910try &#123;    // 可能抛出异常的代码    int result = 10 / 0;&#125; catch (ArithmeticException e) &#123;    // 捕获并处理异常    System.out.println(&quot;发生算术异常：&quot; + e.getMessage());&#125; finally &#123;    // 无论是否发生异常都会执行的代码    System.out.println(&quot;finally 块执行。&quot;);&#125;

四、集合框架1234567891011121314151617// ArrayListArrayList&lt;String&gt; list = new ArrayList&lt;&gt;();list.add(&quot;苹果&quot;);list.add(&quot;香蕉&quot;);list.add(&quot;橙子&quot;);// HashSetHashSet&lt;Integer&gt; set = new HashSet&lt;&gt;();set.add(1);set.add(2);set.add(3);// HashMapHashMap&lt;String, Integer&gt; map = new HashMap&lt;&gt;();map.put(&quot;张三&quot;, 20);map.put(&quot;李四&quot;, 22);int age = map.get(&quot;张三&quot;);
